namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string documentText, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class ExtractiveSummarizer : IDocumentSummarizer
{
    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SentenceSplitRegex().Split(documentText.Trim())
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .Select(s => s.Trim())
            .ToList();

        if (sentences.Count == 0)
            return string.Empty;

        // Score sentences by word frequency
        var wordFrequency = GetWordFrequency(sentences);
        var scored = sentences
            .Select((s, i) => (Sentence: s, Score: ScoreSentence(s, wordFrequency), Index: i))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index)
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    private static Dictionary<string, int> GetWordFrequency(List<string> sentences)
    {
        var frequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in WordSplitRegex().Split(sentence))
            {
                if (word.Length <= 2) continue;
                frequency.TryGetValue(word, out int count);
                frequency[word] = count + 1;
            }
        }
        return frequency;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequency)
    {
        var words = WordSplitRegex().Split(sentence).Where(w => w.Length > 2).ToList();
        if (words.Count == 0) return 0;
        return words.Sum(w => wordFrequency.GetValueOrDefault(w, 0)) / (double)words.Count;
    }

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceSplitRegex();

    [GeneratedRegex(@"\W+")]
    private static partial Regex WordSplitRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummarizeController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest("DocumentText is required.");

        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

